const o=JSON.parse('{"key":"v-759f12ff","path":"/note-book/LinuxOperaSystem/grub2%E6%89%8B%E5%8A%A8%E5%91%BD%E4%BB%A4%E5%BC%95%E5%AF%BC%E6%95%99%E7%A8%8B.html","title":"grub2各种手动命令引导教程","lang":"zh-CN","frontmatter":{"description":"grub2各种手动命令引导教程 手动引导ubuntu的iso镜像文件 从而安装ubuntu，grub&gt;代表命令的开始 假设ubuntu镜像在U盘的第一个分区的根目录下即：(hd0,1)/ubuntu-18.04-desktop-amd64.iso 手动引导下可以按TAB键补全命令、目录以及文件名 #查询所有已安装磁盘并打印详细信息 grub&gt;ls -l #设置根目录分区 grub&gt;set root=(hd0,1) #将Ubuntu.iso位置赋值给变量isofile （这里用变量方便下面不用打一长串文件名） grub&gt;set isofile=/ubuntu-18.04-desktop-amd64.iso #使用grub2的回放技术，把ubuntu.iso的文件内容，投射（挂载）到loop上。在使用这个命令时，你得考虑你的内存足够的大。(hd0,1)iso镜像文件所在分区 grub&gt;loopback loop (hd0,1)$isofile #加载内核，其中(loop),是使用了上一句所投射的设备，其访问的是ubuntu.iso文件的内容，boor=casper将目录casper挂载为boot，iso-scan/filename=$isofile 是利用iso-scan来寻找到你的ubuntu.iso文件所在位置并把所找到的iso文件挂到光驱设备 grub&gt;linux (loop)/casper/vmlinuz boot=casper iso-scan/filename=$isofile quiet splash #initrid.lz是一个镜象文件，里面存的是一些内核要加载的重要文件 grub&gt;initrd (loop)/casper/initrd.lz #根据上面的参数启动系统 grub&gt;boot","head":[["meta",{"property":"og:url","content":"https://paper-dragon.github.io/note-book/LinuxOperaSystem/grub2%E6%89%8B%E5%8A%A8%E5%91%BD%E4%BB%A4%E5%BC%95%E5%AF%BC%E6%95%99%E7%A8%8B.html"}],["meta",{"property":"og:site_name","content":"运维开发绿皮书"}],["meta",{"property":"og:title","content":"grub2各种手动命令引导教程"}],["meta",{"property":"og:description","content":"grub2各种手动命令引导教程 手动引导ubuntu的iso镜像文件 从而安装ubuntu，grub&gt;代表命令的开始 假设ubuntu镜像在U盘的第一个分区的根目录下即：(hd0,1)/ubuntu-18.04-desktop-amd64.iso 手动引导下可以按TAB键补全命令、目录以及文件名 #查询所有已安装磁盘并打印详细信息 grub&gt;ls -l #设置根目录分区 grub&gt;set root=(hd0,1) #将Ubuntu.iso位置赋值给变量isofile （这里用变量方便下面不用打一长串文件名） grub&gt;set isofile=/ubuntu-18.04-desktop-amd64.iso #使用grub2的回放技术，把ubuntu.iso的文件内容，投射（挂载）到loop上。在使用这个命令时，你得考虑你的内存足够的大。(hd0,1)iso镜像文件所在分区 grub&gt;loopback loop (hd0,1)$isofile #加载内核，其中(loop),是使用了上一句所投射的设备，其访问的是ubuntu.iso文件的内容，boor=casper将目录casper挂载为boot，iso-scan/filename=$isofile 是利用iso-scan来寻找到你的ubuntu.iso文件所在位置并把所找到的iso文件挂到光驱设备 grub&gt;linux (loop)/casper/vmlinuz boot=casper iso-scan/filename=$isofile quiet splash #initrid.lz是一个镜象文件，里面存的是一些内核要加载的重要文件 grub&gt;initrd (loop)/casper/initrd.lz #根据上面的参数启动系统 grub&gt;boot"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-11-03T05:37:53.000Z"}],["meta",{"property":"article:author","content":"PaperDragon"}],["meta",{"property":"article:modified_time","content":"2023-11-03T05:37:53.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"grub2各种手动命令引导教程\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2023-11-03T05:37:53.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"PaperDragon\\",\\"url\\":\\"https://github.com/Paper-Dragon\\"}]}"]]},"headers":[{"level":2,"title":"手动引导ubuntu的iso镜像文件","slug":"手动引导ubuntu的iso镜像文件","link":"#手动引导ubuntu的iso镜像文件","children":[]},{"level":2,"title":"手动引导archlinux的iso镜像文件从而安装archlinux","slug":"手动引导archlinux的iso镜像文件从而安装archlinux","link":"#手动引导archlinux的iso镜像文件从而安装archlinux","children":[]},{"level":2,"title":"手动引导Ubuntu","slug":"手动引导ubuntu","link":"#手动引导ubuntu","children":[]},{"level":2,"title":"手动引导uefi启动模式下的Windows。","slug":"手动引导uefi启动模式下的windows。","link":"#手动引导uefi启动模式下的windows。","children":[]},{"level":2,"title":"手动引导bios启动模式下的Windows。","slug":"手动引导bios启动模式下的windows。","link":"#手动引导bios启动模式下的windows。","children":[]}],"git":{"createdTime":1698989873000,"updatedTime":1698989873000,"contributors":[{"name":"PaperDragon-SH","email":"2678885646@qq.com","commits":1}]},"readingTime":{"minutes":2.96,"words":889},"filePathRelative":"note-book/LinuxOperaSystem/grub2手动命令引导教程.md","localizedDate":"2023年11月3日","excerpt":"<h1> grub2各种手动命令引导教程</h1>\\n<h2> 手动引导ubuntu的iso镜像文件</h2>\\n<p>从而安装ubuntu，grub&gt;代表命令的开始</p>\\n<p>假设ubuntu镜像在U盘的第一个分区的根目录下即：(hd0,1)/ubuntu-18.04-desktop-amd64.iso</p>\\n<p>手动引导下可以按TAB键补全命令、目录以及文件名</p>\\n<pre><code>#查询所有已安装磁盘并打印详细信息\\ngrub&gt;ls -l\\n \\n #设置根目录分区\\ngrub&gt;set root=(hd0,1)\\n \\n#将Ubuntu.iso位置赋值给变量isofile （这里用变量方便下面不用打一长串文件名）\\ngrub&gt;set isofile=/ubuntu-18.04-desktop-amd64.iso\\n \\n#使用grub2的回放技术，把ubuntu.iso的文件内容，投射（挂载）到loop上。在使用这个命令时，你得考虑你的内存足够的大。(hd0,1)iso镜像文件所在分区\\ngrub&gt;loopback loop (hd0,1)$isofile\\n \\n#加载内核，其中(loop),是使用了上一句所投射的设备，其访问的是ubuntu.iso文件的内容，boor=casper将目录casper挂载为boot，iso-scan/filename=$isofile 是利用iso-scan来寻找到你的ubuntu.iso文件所在位置并把所找到的iso文件挂到光驱设备\\ngrub&gt;linux (loop)/casper/vmlinuz boot=casper iso-scan/filename=$isofile quiet splash\\n \\n#initrid.lz是一个镜象文件，里面存的是一些内核要加载的重要文件\\ngrub&gt;initrd (loop)/casper/initrd.lz\\n \\n#根据上面的参数启动系统\\ngrub&gt;boot\\n</code></pre>","autoDesc":true}');export{o as data};
